(function(){"use strict";const config=window.loginConfig||{};const initialState=config.initialState||{};const authTypes=config.authTypes||{0:"password",1:"mixed",2:"otp"};const checkUserUrl=config.checkUserUrl||"";const csrfParam=config.csrfParam||"";const csrfToken=config.csrfToken||"";const steps={login:document.getElementById("step-login"),password:document.getElementById("step-password"),otp:document.getElementById("step-otp")};const buttons={next:document.getElementById("next-btn"),submit:document.getElementById("submit-btn"),back:document.getElementById("back-option")};const titles={main:document.getElementById("greeting-title"),sub:document.getElementById("greeting-subtitle")};const nextBtnDefaultHTML="<span>Продолжить</span>"+'<svg class="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">'+'<path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M14 5l7 7m0 0l-7 7m7-7H3" />'+"</svg>";const spinnerHTML='<svg class="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">'+'<circle class="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" stroke-width="4"></circle>'+'<path class="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>'+"</svg>";function showError(message){if(!message)return;var errorBlock=document.getElementById("error-alert");var errorText=document.getElementById("error-text");errorText.textContent=message;errorBlock.classList.remove("hidden");errorBlock.classList.add("animate-shake");setTimeout(function(){errorBlock.classList.remove("animate-shake")},500)}function hideError(){document.getElementById("error-alert").classList.add("hidden")}function checkUser(){hideError();var loginInput=document.getElementById("username");var username=loginInput.value.toLowerCase().trim();if(!username){showError("Пожалуйста, введите логин.");return}buttons.next.innerHTML=spinnerHTML;fetch(checkUserUrl,{method:"POST",headers:{"Content-Type":"application/x-www-form-urlencoded","X-CSRF-Token":csrfToken},body:"username="+encodeURIComponent(username)+"&"+csrfParam+"="+encodeURIComponent(csrfToken)}).then(function(response){return response.json()}).then(function(data){if(data.success){transitionToNextStep(data.username,{type:data.type});loginInput.value=data.username}else{showError(data.message||"Ошибка проверки пользователя");buttons.next.innerHTML=nextBtnDefaultHTML}}).catch(function(error){showError("Ошибка сети: "+error.message);buttons.next.innerHTML=nextBtnDefaultHTML})}function transitionToNextStep(username,scenario){steps.login.classList.add("hidden");titles.main.innerText="Привет, "+username;titles.sub.innerText="Подтвердите вашу личность";buttons.next.classList.add("hidden");buttons.submit.classList.remove("hidden");buttons.back.classList.remove("hidden");if(scenario.type==="password"){steps.password.classList.remove("hidden");document.getElementById("password").focus()}else if(scenario.type==="otp"){steps.otp.classList.remove("hidden");document.getElementById("otp1").focus()}else if(scenario.type==="mixed"){steps.password.classList.remove("hidden");steps.otp.classList.remove("hidden");document.getElementById("password").focus()}}function resetFlow(){hideError();steps.login.classList.remove("hidden");steps.password.classList.add("hidden");steps.otp.classList.add("hidden");buttons.next.classList.remove("hidden");buttons.next.innerHTML=nextBtnDefaultHTML;buttons.submit.classList.add("hidden");buttons.back.classList.add("hidden");titles.main.innerText="Добро пожаловать";titles.sub.innerText="Введите идентификатор для доступа";document.getElementById("username").focus()}function moveToNext(elem,nextFieldID){elem.value=elem.value.replace(/[^0-9]/g,"");if(elem.value.length>=elem.maxLength){if(nextFieldID==="submit-btn"){collectOtp();document.getElementById("submit-btn").click()}else{document.getElementById(nextFieldID).focus()}}collectOtp()}function moveToPrev(event,prevFieldID){if(event.key==="Backspace"&&event.target.value.length===0){document.getElementById(prevFieldID).focus()}setTimeout(collectOtp,0)}function collectOtp(){var code="";document.querySelectorAll(".otp-input").forEach(function(input){code+=input.value});document.getElementById("full_otp_code").value=code}function toggleBlur(){var input=document.getElementById("username");if(input.style.filter==="blur(4px)"){input.style.filter="none"}else{if(input.value)input.style.filter="blur(4px)"}}function handleAuth(e){var btn=document.getElementById("submit-btn");btn.innerHTML="Проверка...";btn.classList.add("opacity-75","cursor-not-allowed")}function init(){var hour=(new Date).getHours();var title=document.getElementById("greeting-title");if(title.innerText==="Добро пожаловать"){if(hour<12)title.innerText="Доброе утро";else if(hour<18)title.innerText="Добрый день";else title.innerText="Добрый вечер"}if(initialState.username){var scenarioType=authTypes[initialState.authType]||"password";transitionToNextStep(initialState.username,{type:scenarioType});if(initialState.hasErrors){showError(initialState.errorMessage)}}}window.checkUser=checkUser;window.resetFlow=resetFlow;window.moveToNext=moveToNext;window.moveToPrev=moveToPrev;window.toggleBlur=toggleBlur;window.handleAuth=handleAuth;window.hideError=hideError;window.showError=showError;if(document.readyState==="loading"){document.addEventListener("DOMContentLoaded",init)}else{init()}})();